const crypto = require('crypto');
const rawBody   = $input.first().binary?.data ? Buffer.from($input.first().binary.data, 'base64').toString('utf8') : JSON.stringify($input.first().json);
const sigHeader = $input.first().headers['x-ghl-signature'] || '';
const secret    = $env.WEBHOOK_SECRET;
if (!secret) throw new Error('WEBHOOK_SECRET no configurado');
if (!sigHeader) throw new Error('HMAC: header X-GHL-Signature ausente');
const receivedHex = sigHeader.startsWith('sha256=') ? sigHeader.slice(7) : sigHeader;
const receivedBuf = Buffer.from(receivedHex, 'hex');
const hmac = crypto.createHmac('sha256', secret);
hmac.update(rawBody);
const expectedBuf = Buffer.from(hmac.digest('hex'), 'hex');
if (receivedBuf.length !== expectedBuf.length || !crypto.timingSafeEqual(receivedBuf, expectedBuf)) {
  throw new Error('HMAC: firma invalida');
}
return $input.all();

const REGEX_GHL_ID      = /^[a-zA-Z0-9_-]{8,50}$/;
const REGEX_LOCATION_ID = /^[a-zA-Z0-9]{10,30}$/;

function cleanStr(val, maxLen) {
  if (val === null || val === undefined) return null;
  const s = String(val).trim().substring(0, maxLen);
  return s.length > 0 ? s : null;
}
function validateGHLId(val) {
  if (!val) return null;
  const s = String(val).trim();
  return REGEX_GHL_ID.test(s) ? s : null;
}
function parseISODate(val) {
  if (!val) return null;
  const ts = Date.parse(String(val));
  return isNaN(ts) ? null : new Date(ts).toISOString();
}
function parseIntSafe(val) {
  if (val === null || val === undefined || val === '') return null;
  const n = parseInt(val, 10);
  return isNaN(n) ? null : n;
}

const raw  = $input.first().json;
const body = raw.body || raw;

const conversation_id = validateGHLId(body.id || body.conversationId);
const contact_id      = validateGHLId(body.contactId || body.contact_id);
const _loc_raw = (raw.params && raw.params.location_id)
  ? raw.params.location_id
  : (body.locationId || '');
const location_id     = REGEX_LOCATION_ID.test(String(_loc_raw).trim()) ? String(_loc_raw).trim() : null;

if (!conversation_id) throw new Error('conversation_id invalido');
if (!contact_id)      throw new Error('contact_id invalido');
if (!location_id)     throw new Error('location_id invalido');

const conv = {
  conversation_id,
  contact_id,
  location_id,
  channel_type:        cleanStr(body.type || body.channelType || body.channel_type, 30),
  inbox_id:            validateGHLId(body.inboxId),
  inbox_name:          cleanStr(body.inboxName, 200),
  assigned_user_id:    validateGHLId(body.userId || body.assignedUserId),
  assigned_user_name:  cleanStr(body.userName || body.assignedUserName, 200),
  status:              cleanStr(body.status, 20),
  unread_count:        parseIntSafe(body.unreadCount) || 0,
  last_message_at:     parseISODate(body.lastMessageDate || body.lastMessageAt),
  ghl_created_at:      parseISODate(body.dateAdded || body.createdAt),
  synced_at:           new Date().toISOString()
};

// Mensajes adjuntos al evento (si los hay)
const messages = Array.isArray(body.messages) ? body.messages : [];

return [{ json: { conv, messages, rawMessage: body.lastMessage || null } }];

const REGEX_GHL_ID      = /^[a-zA-Z0-9_-]{8,50}$/;
const REGEX_LOCATION_ID = /^[a-zA-Z0-9]{10,30}$/;
const REGEX_EMAIL       = /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*\.[a-zA-Z]{2,}$/;

function cleanStr(val, maxLen) {
  if (!val) return null;
  const s = String(val).trim().substring(0, maxLen);
  return s.length > 0 ? s : null;
}
function validateGHLId(val) {
  if (!val) return null;
  const s = String(val).trim();
  return REGEX_GHL_ID.test(s) ? s : null;
}
function validateEmail(val) {
  if (!val) return null;
  const n = String(val).toLowerCase().trim().substring(0, 255);
  return REGEX_EMAIL.test(n) ? n : null;
}
function parseISODate(val) {
  if (!val) return null;
  const ts = Date.parse(String(val));
  return isNaN(ts) ? null : new Date(ts).toISOString();
}

const data  = $('Sanitizar Conversacion').first().json;
const msg   = data.rawMessage || {};
const conv  = data.conv;

const message_id = validateGHLId(msg.id || msg.messageId);
if (!message_id) throw new Error('message_id invalido en el mensaje adjunto');

const direction = String(msg.direction || msg.messageDirection || '').toLowerCase();
if (!['inbound', 'outbound'].includes(direction)) {
  throw new Error('direction invalido: ' + direction);
}

return [{ json: {
  message_id,
  conversation_id: conv.conversation_id,
  contact_id:      conv.contact_id,
  location_id:     conv.location_id,
  message_type:    cleanStr(msg.messageType || msg.type, 30),
  direction,
  body:            msg.body ? String(msg.body).substring(0, 65535) : null,
  subject:         cleanStr(msg.subject, 500),
  from_email:      validateEmail(msg.from || msg.fromEmail),
  to_email:        validateEmail(msg.to   || msg.toEmail),
  email_message_id: cleanStr(msg.emailMessageId, 200),
  wa_message_id:   cleanStr(msg.waMessageId, 200),
  wa_status:       cleanStr(msg.waStatus, 20),
  user_id:         validateGHLId(msg.userId),
  user_name:       cleanStr(msg.userName, 200),
  sent_at:         parseISODate(msg.dateAdded || msg.createdAt) || new Date().toISOString()
} }];
